import{_ as a,o as n,c as o,ak as l}from"./chunks/framework.DLt_otXO.js";const d=JSON.parse('{"title":"重定向和别名","description":"","frontmatter":{"title":"重定向和别名","date":"2021-12-30T16:11:43.000Z","permalink":"/pages/1a520a/","categories":["框架","VueRouter"],"tags":[null]},"headers":[],"relativePath":"框架/VueRouter/重定向和别名.md","filePath":"框架/VueRouter/重定向和别名.md","lastUpdated":1777258973000}'),e={name:"框架/VueRouter/重定向和别名.md"};function p(t,s,c,r,E,i){return n(),o("div",null,[...s[0]||(s[0]=[l(`<h2 id="_1-重定向" tabindex="-1">1. 重定向 <a class="header-anchor" href="#_1-重定向" aria-label="Permalink to “1. 重定向”">​</a></h2><p>重定向也是通过<code>routes</code>配置来完成的，下面的例子式从<code>/a</code>重定向到<code>/b</code>:</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki github-dark" style="background-color:#24292e;color:#e1e4e8;" tabindex="0" dir="ltr"><code><span class="line"><span style="color:#F97583;">const</span><span style="color:#79B8FF;"> routes</span><span style="color:#F97583;"> =</span><span style="color:#E1E4E8;"> [{ path: </span><span style="color:#9ECBFF;">&quot;/home&quot;</span><span style="color:#E1E4E8;">, redirect: </span><span style="color:#9ECBFF;">&quot;/&quot;</span><span style="color:#E1E4E8;"> }];</span></span></code></pre></div><p>重定向的目标也可以是一个<strong>命名路由</strong></p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki github-dark" style="background-color:#24292e;color:#e1e4e8;" tabindex="0" dir="ltr"><code><span class="line"><span style="color:#F97583;">const</span><span style="color:#79B8FF;"> routes</span><span style="color:#F97583;"> =</span><span style="color:#E1E4E8;"> [{ path: </span><span style="color:#9ECBFF;">&quot;/home&quot;</span><span style="color:#E1E4E8;">, redirect: { name: </span><span style="color:#9ECBFF;">&quot;/homepage&quot;</span><span style="color:#E1E4E8;"> } }];</span></span></code></pre></div><p>甚至是一个方法，动态返回重定向目标：</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki github-dark" style="background-color:#24292e;color:#e1e4e8;" tabindex="0" dir="ltr"><code><span class="line"><span style="color:#F97583;">const</span><span style="color:#79B8FF;"> routes</span><span style="color:#F97583;"> =</span><span style="color:#E1E4E8;"> [</span></span>
<span class="line"><span style="color:#E1E4E8;">  {</span></span>
<span class="line"><span style="color:#6A737D;">    // /search/screens -&gt; /search?q=screens</span></span>
<span class="line"><span style="color:#E1E4E8;">    path: </span><span style="color:#9ECBFF;">&quot;/search/:searchText&quot;</span><span style="color:#E1E4E8;">,</span></span>
<span class="line"><span style="color:#B392F0;">    redirect</span><span style="color:#E1E4E8;">: (</span><span style="color:#FFAB70;">to</span><span style="color:#E1E4E8;">) </span><span style="color:#F97583;">=&gt;</span><span style="color:#E1E4E8;"> {</span></span>
<span class="line"><span style="color:#6A737D;">      // 方法接收目标路由作为参数</span></span>
<span class="line"><span style="color:#6A737D;">      // return 重定向的字符串路径/路径对象</span></span>
<span class="line"><span style="color:#F97583;">      return</span><span style="color:#E1E4E8;"> { path: </span><span style="color:#9ECBFF;">&quot;/search&quot;</span><span style="color:#E1E4E8;">, query: { q: to.params.searchText } };</span></span>
<span class="line"><span style="color:#E1E4E8;">    },</span></span>
<span class="line"><span style="color:#E1E4E8;">  },</span></span>
<span class="line"><span style="color:#E1E4E8;">  {</span></span>
<span class="line"><span style="color:#E1E4E8;">    path: </span><span style="color:#9ECBFF;">&quot;/search&quot;</span><span style="color:#E1E4E8;">,</span></span>
<span class="line"><span style="color:#6A737D;">    // ...</span></span>
<span class="line"><span style="color:#E1E4E8;">  },</span></span>
<span class="line"><span style="color:#E1E4E8;">];</span></span></code></pre></div><p>在写<code>redirect</code>的时候，可以省略<code>component</code>配置，因为它从来没有被直接访问过，所以没有组件要渲染。 唯一的例外是嵌套路由：如果一个路由记录有 <code>children</code> 和 <code>redirect</code> 属性，它也应该有 <code>component</code> 属性。</p><h2 id="别名" tabindex="-1">别名 <a class="header-anchor" href="#别名" aria-label="Permalink to “别名”">​</a></h2><p>重定向是指当用户访问 <code>/home</code> 时，URL 会被 <code>/</code> 替换，然后匹配成 <code>/</code>。那么什么是别名呢？ 将 <code>/</code>别名为 <code>/home</code>，意味着当用户访问 <code>/home</code> 时，URL 仍然是 <code>/home</code>，但会被匹配为用户正在访问 <code>/</code>。</p><p>上面对应的路由配置为：</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki github-dark" style="background-color:#24292e;color:#e1e4e8;" tabindex="0" dir="ltr"><code><span class="line"><span style="color:#F97583;">const</span><span style="color:#79B8FF;"> routes</span><span style="color:#F97583;"> =</span><span style="color:#E1E4E8;"> [{ path: </span><span style="color:#9ECBFF;">&quot;/&quot;</span><span style="color:#E1E4E8;">, component: Homepage, alias: </span><span style="color:#9ECBFF;">&quot;/home&quot;</span><span style="color:#E1E4E8;"> }];</span></span></code></pre></div><p>通过别名，我们可以自由的将<code>UI</code>结构映射到一个任意的<code>URL</code>，而不受配置的嵌套结构的限制。使别名以 / 开头，以使嵌套路径中的路径成为绝对路径。你甚至可以将两者结合起来，用一个数组提供多个别名：</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki github-dark" style="background-color:#24292e;color:#e1e4e8;" tabindex="0" dir="ltr"><code><span class="line"><span style="color:#F97583;">const</span><span style="color:#79B8FF;"> routes</span><span style="color:#F97583;"> =</span><span style="color:#E1E4E8;"> [</span></span>
<span class="line"><span style="color:#E1E4E8;">  {</span></span>
<span class="line"><span style="color:#E1E4E8;">    path: </span><span style="color:#9ECBFF;">&quot;/users&quot;</span><span style="color:#E1E4E8;">,</span></span>
<span class="line"><span style="color:#E1E4E8;">    component: UsersLayout,</span></span>
<span class="line"><span style="color:#E1E4E8;">    children: [</span></span>
<span class="line"><span style="color:#6A737D;">      // 为这 3 个 URL 呈现 UserList</span></span>
<span class="line"><span style="color:#6A737D;">      // - /users</span></span>
<span class="line"><span style="color:#6A737D;">      // - /users/list</span></span>
<span class="line"><span style="color:#6A737D;">      // - /people</span></span>
<span class="line"><span style="color:#E1E4E8;">      { path: </span><span style="color:#9ECBFF;">&quot;&quot;</span><span style="color:#E1E4E8;">, component: UserList, alias: [</span><span style="color:#9ECBFF;">&quot;/people&quot;</span><span style="color:#E1E4E8;">, </span><span style="color:#9ECBFF;">&quot;list&quot;</span><span style="color:#E1E4E8;">] },</span></span>
<span class="line"><span style="color:#E1E4E8;">    ],</span></span>
<span class="line"><span style="color:#E1E4E8;">  },</span></span>
<span class="line"><span style="color:#E1E4E8;">];</span></span></code></pre></div><p>如果你的路由有参数，请确保在任何绝对别名中包含它们：</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki github-dark" style="background-color:#24292e;color:#e1e4e8;" tabindex="0" dir="ltr"><code><span class="line"><span style="color:#F97583;">const</span><span style="color:#79B8FF;"> routes</span><span style="color:#F97583;"> =</span><span style="color:#E1E4E8;"> [</span></span>
<span class="line"><span style="color:#E1E4E8;">  {</span></span>
<span class="line"><span style="color:#E1E4E8;">    path: </span><span style="color:#9ECBFF;">&quot;/users/:id&quot;</span><span style="color:#E1E4E8;">,</span></span>
<span class="line"><span style="color:#E1E4E8;">    component: UsersByIdLayout,</span></span>
<span class="line"><span style="color:#E1E4E8;">    children: [</span></span>
<span class="line"><span style="color:#6A737D;">      // 为这 3 个 URL 呈现 UserDetails</span></span>
<span class="line"><span style="color:#6A737D;">      // - /users/24</span></span>
<span class="line"><span style="color:#6A737D;">      // - /users/24/profile</span></span>
<span class="line"><span style="color:#6A737D;">      // - /24</span></span>
<span class="line"><span style="color:#E1E4E8;">      { path: </span><span style="color:#9ECBFF;">&quot;profile&quot;</span><span style="color:#E1E4E8;">, component: UserDetails, alias: [</span><span style="color:#9ECBFF;">&quot;/:id&quot;</span><span style="color:#E1E4E8;">, </span><span style="color:#9ECBFF;">&quot;&quot;</span><span style="color:#E1E4E8;">] },</span></span>
<span class="line"><span style="color:#E1E4E8;">    ],</span></span>
<span class="line"><span style="color:#E1E4E8;">  },</span></span>
<span class="line"><span style="color:#E1E4E8;">];</span></span></code></pre></div>`,16)])])}const u=a(e,[["render",p]]);export{d as __pageData,u as default};
